-- 1. Schema Definitions

CREATE TABLE IF NOT EXISTS users (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    username TEXT NOT NULL UNIQUE,
    email TEXT UNIQUE,
    password TEXT NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS clients (
    client_name TEXT PRIMARY KEY,
    company TEXT,
    address TEXT,
    portal_token TEXT UNIQUE,
    portal_enabled BOOLEAN DEFAULT TRUE,
    archived BOOLEAN DEFAULT FALSE,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS engineers (
    contact_name TEXT PRIMARY KEY,
    email TEXT,
    phone TEXT,
    address TEXT,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS site_contacts (
    contact_name TEXT PRIMARY KEY,
    email TEXT,
    phone TEXT,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS brands (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    brand_name TEXT UNIQUE,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS client_sites (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    client_name TEXT REFERENCES clients(client_name),
    site_name TEXT NOT NULL,
    address TEXT,
    brand_name TEXT REFERENCES brands(brand_name),
    archived BOOLEAN DEFAULT FALSE,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS jobs (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    job_number TEXT UNIQUE,
    date DATE NOT NULL,
    time TIME NOT NULL,
    brand TEXT,
    site_name TEXT,
    priority TEXT,
    status TEXT DEFAULT 'Scheduled',
    job_type TEXT DEFAULT 'Extraction',
    client_name TEXT REFERENCES clients(client_name),
    company TEXT,
    address TEXT,
    engineer_contact_name TEXT REFERENCES engineers(contact_name),
    engineer_email TEXT,
    engineer_phone TEXT,
    site_contact_name TEXT REFERENCES site_contacts(contact_name),
    site_contact_email TEXT,
    site_contact_phone TEXT,
    notes TEXT,
    photos TEXT,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS engineer_diary (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    engineer_name TEXT REFERENCES engineers(contact_name),
    date DATE NOT NULL,
    status TEXT,
    notes TEXT,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS password_resets (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    email TEXT UNIQUE,
    token TEXT,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS extraction_reports (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    job_number TEXT,
    company TEXT,
    date DATE,
    time TIME,
    brand TEXT,
    address TEXT,
    contact_name TEXT,
    contact_number TEXT,
    job_type TEXT DEFAULT 'Extraction',
    status TEXT DEFAULT 'Draft',
    risk_pre INTEGER,
    risk_post INTEGER,
    remedial_requirements TEXT,
    risk_improvements TEXT,
    cleaning_interval_current TEXT,
    cleaning_interval_recommended TEXT,
    sketch_details TEXT,
    issue_description TEXT,
    work_done TEXT,
    recommendations TEXT,
    photos_taken TEXT,
    photos_path TEXT,
    client_signature TEXT,
    engineer_signature TEXT,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS extraction_micron_readings (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    report_id BIGINT REFERENCES extraction_reports(id),
    location TEXT,
    description TEXT,
    pre_clean INTEGER,
    post_clean INTEGER
);

CREATE TABLE IF NOT EXISTS extraction_photos (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    report_id BIGINT REFERENCES extraction_reports(id),
    photo_type TEXT,
    photo_path TEXT,
    caption TEXT,
    inspection_item TEXT
);

CREATE TABLE IF NOT EXISTS extraction_inspection_items (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    report_id BIGINT REFERENCES extraction_reports(id),
    item_name TEXT,
    pre_clean TEXT,
    success BOOLEAN DEFAULT FALSE,
    pass_status BOOLEAN DEFAULT FALSE,
    fail_status BOOLEAN DEFAULT FALSE,
    advice TEXT,
    initial TEXT
);

CREATE TABLE IF NOT EXISTS extraction_filter_items (
    id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    report_id BIGINT REFERENCES extraction_reports(id),
    filter_type TEXT,
    height INTEGER,
    width INTEGER,
    depth INTEGER,
    quantity INTEGER,
    pass_status BOOLEAN DEFAULT FALSE,
    fail_status BOOLEAN DEFAULT FALSE
);

